async (params, browser) => {
  // Open Slack
  await browser.open('https://app.slack.com')

  // Let Slack load
  await browser.wait(3000)

  // Send message via Slack API
  const result = await browser.evaluate(`const localConfig = localStorage.getItem('localConfig_v2'); if (!localConfig) throw new Error('Not logged into Slack - localConfig_v2 not found'); const config = JSON.parse(localConfig); const teamId = Object.keys(config.teams)[0]; const token = config.teams[teamId].token; if (!token) throw new Error('Slack token not found'); const chanResp = await fetch('/api/conversations.list?types=public_channel,private_channel&limit=200', { method: 'POST', headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/x-www-form-urlencoded' } }); if (!chanResp.ok) throw new Error('Failed to list channels'); const chanData = await chanResp.json(); const channel = chanData.channels?.find(c => c.name === params.channel_name); if (!channel) return { success: false, message: 'Channel not found: ' + params.channel_name + '' }; const resp = await fetch('/api/chat.postMessage', { method: 'POST', headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' }, body: JSON.stringify({ channel: channel.id, text: params.message }) }); const data = await resp.json(); if (!data.ok) throw new Error('Send failed: ' + data.error); return { success: true, channel: '' + params.channel_name + '', ts: data.ts }`)

  return result
}
